('chunk_10c37e83c5f5ae27bc','file_04bb580a3d99034261','history.md','Vijayanagara Empire','- **Dates:** c. **1336 CE – 1646 CE** (peak in the 15th–early 16th century).
- **Location:** South India (Deccan); capital **Vijayanagara** (Hampi), on the Tungabhadra River.
- **Rise factors:** Founded by **Harihara I and Bukka Raya I** (Sangama dynasty); strong military, wealth from agriculture and the cotton/spice/horse trade; role as a major Hindu power in the Deccan.
- **Governance:** Centralised monarchy with a military-fief (**nayaka**) system in which nobles held land in return for maintaining troops; provincial administration; substantial revenue system.
- **Achievements:** Splendid capital at **Hampi** (temples, markets, irrigation, UNESCO World Heritage); flourishing trade, art and literature; peak under **Krishnadevaraya** (r. 1509–1529).
- **Causes of decline:** Decisive defeat by a coalition of Deccan Sultanates at the **Battle of Talikota (1565)**, after which Vijayanagara city was sacked; the empire fragmented and declined, lingering until c. 1646.','{"1336":1,"1509":1,"1529":1,"1565":1,"1646":2,"vijayanagara":3,"empire":2,"dates":1,"peak":2,"the":6,"15th":1,"early":1,"16th":1,"century":1,"location":1,"south":1,"india":1,"deccan":3,"capital":2,"hampi":2,"tungabhadra":1,"river":1,"rise":1,"factors":1,"founded":1,"harihara":1,"and":4,"bukka":1,"raya":1,"sangama":1,"dynasty":1,"strong":1,"military":2,"wealth":1,"from":1,"agriculture":1,"cotton":1,"spice":1,"horse":1,"trade":2,"role":1,"major":1,"hindu":1,"power":1,"governance":1,"centralised":1,"monarchy":1,"with":1,"fief":1,"nayaka":1,"system":2,"which":2,"nobles":1,"held":1,"land":1,"return":1,"for":1,"maintaining":1,"troops":1,"provincial":1,"administration":1,"substantial":1,"revenue":1,"achievements":1,"splendid":1,"temples":1,"markets":1,"irrigation":1,"unesco":1,"world":1,"heritage":1,"flourishing":1,"art":1,"literature":1,"under":1,"krishnadevaraya":1,"causes":1,"decline":1,"decisive":1,"defeat":1,"coalition":1,"sultanates":1,"battle":1,"talikota":1,"after":1,"city":1,"was":1,"sacked":1,"fragmented":1,"declined":1,"lingering":1,"until":1}'::jsonb),
